package il.co.dcd.composermapper.index; import il.co.dcd.composermapper.model.DiscoveredFile; import java.util.List;
public class IndexBuildService { private final IniMappingIndexer ini=new IniMappingIndexer(); private final JavaClassIndexer javaIdx=new JavaClassIndexer(); private final XmlDefinitionIndexer xml=new XmlDefinitionIndexer(); public Indexes build(List<DiscoveredFile> files){ Indexes x=Indexes.create(); for(var f:files) if(f.type()==DiscoveredFile.FileType.INI) ini.index(f.path(),x); for(var f:files) if(f.type()==DiscoveredFile.FileType.JAVA) javaIdx.index(f.path(),x); for(var f:files) if(f.type()==DiscoveredFile.FileType.XML) xml.index(f.path(),x); xml.finalizeUnresolved(x); return x; } }
